import { notFound } from 'next/navigation';

interface Post {
  userId: number;
  id: number;
  title: string;
  body: string;
}

interface Comment {
  postId: number;
  id: number;
  name: string;
  email: string;
  body: string;
}

interface PageProps {
  params: Promise<{ id: string }>;
}

export const revalidate = 300;

export async function generateStaticParams(): Promise<{ id: string }[]> {
  const res = await fetch('https://jsonplaceholder.typicode.com/posts');
  const posts: Post[] = await res.json();

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

export default async function BlogPost({ params }: PageProps) {
  const { id } = await params;

  try {
    const [postRes, commentsRes] = await Promise.all([
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
        next: { revalidate: 300 },
      }),
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
        next: { revalidate: 300 },
      }),
    ]);

    if (!postRes.ok) {
      notFound();
    }

    const post: Post = await postRes.json();
    const comments: Comment[] = await commentsRes.json();

    return (
      <article>
        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}

import { NextRequest, NextResponse } from 'next/server';

interface Post {
  id: number;
  title: string;
  content: string;
  createdAt: string;
}

interface PostBody {
  title?: string;
  content?: string;
}

export async function GET(): Promise<NextResponse<Post[]>> {
  const posts: Post[] = [
    { id: 1, title: 'First Post', content: 'This is the first post' },
    { id: 2, title: 'Second Post', content: 'This is the second post' },
  ].map((p) => ({ ...p, createdAt: new Date().toISOString() }));

  return NextResponse.json(posts);
}

export async function POST(
  request: NextRequest
): Promise<NextResponse<Post | { error: string }>> {
  const body: PostBody = await request.json();
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json(
      { error: 'Title and content are required' },
      { status: 400 }
    );
  }

  const newPost: Post = {
    id: Date.now(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(newPost, { status: 201 });
}

import { NextRequest, NextResponse } from 'next/server';

interface Post {
  id: number;
  title: string;
  content: string;
  createdAt: string;
  updatedAt?: string;
}

interface PostBody {
  title?: string;
  content?: string;
}

interface RouteParams {
  params: Promise<{ id: string }>;
}

export async function GET(
  _request: NextRequest,
  { params }: RouteParams
): Promise<NextResponse<Post>> {
  const { id } = await params;

  const post: Post = {
    id: parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(
  request: NextRequest,
  { params }: RouteParams
): Promise<NextResponse<Post>> {
  const { id } = await params;
  const body: PostBody = await request.json();
  const { title, content } = body;

  const updatedPost: Post = {
    id: parseInt(id, 10),
    title: title || `Post ${id}`,
    content: content || `Updated content for post ${id}`,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(
  _request: NextRequest,
  { params }: RouteParams
): Promise<NextResponse<{ message: string }>> {
  const { id } = await params;

  return NextResponse.json({
    message: `Post ${id} deleted successfully`,
  });
}
